// // This module compares two 2-bit inputs, A and B, and returns a 2-bit output, Z. If A is less than B, Z should be 2'b01. If A is greater than B, Z should be 2'b10. If A is equal to B, Z should be 2'b11.
module two_bit_comparator (
  input [1:0] A,
  input [1:0] B,
  output reg [1:0] Z
);

  always @* begin
    if (A > B) begin
      Z = 2'b01;
    end else if (A < B) begin
      Z = 2'b10;
    end else begin
      Z = 2'b11;
    end
  end

endmodule
